class Solution {
public:
    vector<int> twoSum(vector<int>& numbers, int target) {
        int n = numbers.size();

        int l = 0, r = 1;
        while(true){
            if(l == r){
                r++;
                continue;
            }
            int val = numbers[l] + numbers[r];
            if(val == target)
                return {l+1, r+1};
            else if (val < target)
                r++;
            else
                l++;

        }

        return {-1};

    }
};

