class Solution {
    public:
        vector<int> twoSum(vector<int>& numbers, int target) {
            int n = numbers.size();

            int l = 0, r = n-1;
            while(true){

                int val = numbers[l] + numbers[r];
                if(val == target)
                    return {l+1, r+1};
                else if (val > target)
                    r--;
